### 3. How PretrainedMixin Works

**File Path:** `src/models.js` **Lines 7843-7915**

The `PretrainedMixin` class provides the core `from_pretrained()` method that all Auto classes inherit:

```javascript
export class PretrainedMixin {
    static MODEL_CLASS_MAPPINGS = null;
    static BASE_IF_FAIL = false;

    /** @type {typeof PreTrainedModel.from_pretrained} */
    static async from_pretrained(pretrained_model_name_or_path, {
        progress_callback = null,
        config = null,
        cache_dir = null,
        local_files_only = false,
        revision = 'main',
        model_file_name = null,
        subfolder = 'onnx',
        device = null,
        dtype = null,
        use_external_data_format = null,
        session_options = {},
    } = {}) {
        // Loads config first
        options.config = await AutoConfig.from_pretrained(pretrained_model_name_or_path, options);

        // Looks up model_type in MODEL_CLASS_MAPPINGS
        const model_type = options.config.model_type;
        for (const MODEL_CLASS_MAPPING of this.MODEL_CLASS_MAPPINGS) {
            let modelInfo = MODEL_CLASS_MAPPING.get(model_type);
            // ... fallback logic ...
            return await modelInfo[1].from_pretrained(pretrained_model_name_or_path, options);
        }
    }
}
```

The method:
1. Loads the model config using `AutoConfig.from_pretrained()`
2. Extracts the `model_type` from the config
3. Looks up the model type in the `MODEL_CLASS_MAPPINGS`
4. Delegates to the specific model class's `from_pretrained()` method

